from infi.clickhouse_orm.query import Q

def to_sql(self, model_cls):
    if self._fovs:
        sql = ' {} '.format(self._mode).join(fov.to_sql(model_cls) for fov in self._fovs)
    else:
        if self._l_child and self._r_child:
            sql = '({} {} {})'.format(
                    self._l_child.to_sql(
